package main

import (
	"bytes"
	"fmt"
	"os"
	"os/exec"
)

// QuerySLBAndExport executes the aliyun CLI command to describe SLB,
// processes the output with jq, and saves it to the specified file.
// Returns the stdout of the command pipeline and any error encountered.
func QuerySLBAndExport(loadBalancerName string, outputFile string) (string, error) {
	if loadBalancerName == "" {
		return "", fmt.Errorf("loadBalancerName must not be empty")
	}
	if outputFile == "" {
		return "", fmt.Errorf("outputFile must not be empty")
	}

	// Set up aliyun command
	aliyunCmd := exec.Command("aliyun", "slb", "DescribeLoadBalancers", "--LoadBalancerName", loadBalancerName)
	var aliyunStderr bytes.Buffer
	aliyunCmd.Stderr = &aliyunStderr

	// Create pipe from aliyun stdout to jq stdin
	aliyunStdout, err := aliyunCmd.StdoutPipe()
	if err != nil {
		return "", fmt.Errorf("failed to create stdout pipe for aliyun command: %w", err)
	}

	// Set up jq command
	jqCmd := exec.Command("jq", ".LoadBalancers.LoadBalancer[]")
	jqCmd.Stdin = aliyunStdout
	var jqStdout bytes.Buffer
	var jqStderr bytes.Buffer
	jqCmd.Stdout = &jqStdout
	jqCmd.Stderr = &jqStderr

	// Start jq first (it will wait for input from aliyun)
	if err := jqCmd.Start(); err != nil {
		return "", fmt.Errorf("failed to start jq command: %w", err)
	}

	// Run aliyun command (starts and waits for completion)
	if err := aliyunCmd.Run(); err != nil {
		// Clean up jq process
		_ = jqCmd.Process.Kill()
		_ = jqCmd.Wait()
		return "", fmt.Errorf("aliyun command failed: %w, stderr: %q", err, aliyunStderr.String())
	}

	// Wait for jq to finish processing
	if err := jqCmd.Wait(); err != nil {
		return "", fmt.Errorf("jq command failed: %w, stderr: %q", err, jqStderr.String())
	}

	// Write the result to the output file
	outputContent := jqStdout.Bytes()
	if err := os.WriteFile(outputFile, outputContent, 0644); err != nil {
		return string(outputContent), fmt.Errorf("failed to write output file %q: %w", outputFile, err)
	}

	return string(outputContent), nil
}

