package main

import (
	"bytes"
	"fmt"
	"os"
	"os/exec"
)

func QuerySLBAndExport(loadBalancerName string, outputFile string) (string, error) {
	// Create the aliyun SLB query command
	aliyunCmd := exec.Command("aliyun", "slb", "DescribeLoadBalancers", "--LoadBalancerName", loadBalancerName)
	// Create the jq formatting command
	jqCmd := exec.Command("jq", ".LoadBalancers.LoadBalancer[]")

	// Connect aliyun command's stdout to jq command's stdin
	var err error
	jqCmd.Stdin, err = aliyunCmd.StdoutPipe()
	if err != nil {
		return "", fmt.Errorf("failed to create pipe between aliyun and jq: %w", err)
	}

	// Open output file for writing
	outFile, err := os.Create(outputFile)
	if err != nil {
		return "", fmt.Errorf("failed to create output file %s: %w", outputFile, err)
	}
	defer outFile.Close()

	// Redirect jq's stdout to the output file
	jqCmd.Stdout = outFile

	// Capture stderr from both commands for error reporting
	var aliyunStderr, jqStderr bytes.Buffer
	aliyunCmd.Stderr = &aliyunStderr
	jqCmd.Stderr = &jqStderr

	// Start jq command first (downstream of the pipe)
	if err := jqCmd.Start(); err != nil {
		return jqStderr.String(), fmt.Errorf("failed to start jq command: %w", err)
	}

	// Start aliyun command (upstream of the pipe)
	if err := aliyunCmd.Start(); err != nil {
		return aliyunStderr.String(), fmt.Errorf("failed to start aliyun command: %w", err)
	}

	// Wait for aliyun command to complete
	if err := aliyunCmd.Wait(); err != nil {
		return aliyunStderr.String(), fmt.Errorf("aliyun command execution failed: %w", err)
	}

	// Wait for jq command to complete
	if err := jqCmd.Wait(); err != nil {
		return jqStderr.String(), fmt.Errorf("jq command execution failed: %w", err)
	}

	// Return success message
	successMsg := fmt.Sprintf("Successfully exported SLB information to %s", outputFile)
	return successMsg, nil
}

func main() {
	if len(os.Args) != 3 {
		fmt.Printf("Usage: %s <loadBalancerName> <outputFile>\n", os.Args[0])
		os.Exit(1)
	}

	loadBalancerName := os.Args[1]
	outputFile := os.Args[2]

	result, err := QuerySLBAndExport(loadBalancerName, outputFile)
	if err != nil {
		fmt.Printf("Error executing command: %v\nCommand output: %s\n", err, result)
		os.Exit(1)
	}

	fmt.Println(result)
}

