// processes the output with jq, and saves it to the specified file.
// Returns the stderr output of the command pipeline and any error encountered.
func QuerySLBAndExport(loadBalancerName string, outputFile string) (string, error) {
	// Create the aliyun command with direct arguments (no shell injection risk)
	aliyunCmd := exec.Command("aliyun", "slb", "DescribeLoadBalancers", "--LoadBalancerName", loadBalancerName)

	// Create the jq command with the filter as a direct argument
	jqCmd := exec.Command("jq", ".LoadBalancers.LoadBalancer[]")

	// Buffer to capture stderr from both commands
	var stderrBuf bytes.Buffer
	aliyunCmd.Stderr = &stderrBuf
	jqCmd.Stderr = &stderrBuf

	// Set up pipe from aliyun's stdout to jq's stdin
	aliyunStdout, err := aliyunCmd.StdoutPipe()
	if err != nil {
		return stderrBuf.String(), fmt.Errorf("failed to create aliyun stdout pipe: %w, stderr: %s", err, stderrBuf.String())
	}
	jqCmd.Stdin = aliyunStdout

	// Open the output file for writing (create/truncate, same as shell >)
	outputFileHandle, err := os.Create(outputFile)
	if err != nil {
		return stderrBuf.String(), fmt.Errorf("failed to create output file: %w, stderr: %s", err, stderrBuf.String())
	}
	defer outputFileHandle.Close() // Ensure file is closed when done

	// Connect jq's stdout to the output file
	jqCmd.Stdout = outputFileHandle

	// Start the aliyun command first
	if err := aliyunCmd.Start(); err != nil {
		return stderrBuf.String(), fmt.Errorf("failed to start aliyun command: %w, stderr: %s", err, stderrBuf.String())
	}

	// Start the jq command
	if err := jqCmd.Start(); err != nil {
		// Wait for aliyun to avoid zombie process, ignore error since jq failed to start
		_ = aliyunCmd.Wait()
		return stderrBuf.String(), fmt.Errorf("failed to start jq command: %w, stderr: %s", err, stderrBuf.String())
	}

	// Wait for aliyun to complete
	if err := aliyunCmd.Wait(); err != nil {
		// Wait for jq to complete as well to avoid zombies
		_ = jqCmd.Wait()
		return stderrBuf.String(), fmt.Errorf("aliyun command failed: %w, stderr: %s", err, stderrBuf.String())
	}

	// Wait for jq to complete
	if err := jqCmd.Wait(); err != nil {
		return stderrBuf.String(), fmt.Errorf("jq command failed: %w, stderr: %s", err, stderrBuf.String())
	}

	// All steps succeeded, return any stderr output (may be empty)
	return stderrBuf.String(), nil
}

