		return combinedOutput, fmt.Errorf("jq command failed: %w, output: %s", err, combinedOutput)
	}

	// Step 3: Write jq's stdout to the output file, using 0666 permissions (before umask) to match shell behavior
	if err := os.WriteFile(outputFile, jqStdout.Bytes(), 0666); err!= nil {
