// Returns the combined stderr of the commands and any error encountered.
func QuerySLBAndExport(loadBalancerName string, outputFile string) (string, error) {
	// Create the output file (truncate if exists, create if not, mode 0666 before umask)
	outFile, err := os.Create(outputFile)
	if err != nil {
		return "", fmt.Errorf("failed to create output file: %w", err)
	}
	defer outFile.Close()

	// Initialize the aliyun command with direct arguments (no shell interpolation)
	aliyunCmd := exec.Command("aliyun", "slb", "DescribeLoadBalancers", "--LoadBalancerName", loadBalancerName)
	// Create a pipe to connect aliyun's stdout to jq's stdin
	aliyunStdout, err := aliyunCmd.StdoutPipe()
	if err != nil {
		return "", fmt.Errorf("failed to create pipe for aliyun: %w", err)
	}
	// Capture aliyun's stderr for error reporting
	var aliyunStderr bytes.Buffer
	aliyunCmd.Stderr = &aliyunStderr

	// Initialize jq command with direct arguments
	jqCmd := exec.Command("jq", ".LoadBalancers.LoadBalancer[]")
	jqCmd.Stdin = aliyunStdout
	// Direct jq's stdout to the output file instead of shell redirection
	jqCmd.Stdout = outFile
	// Capture jq's stderr for error reporting
	var jqStderr bytes.Buffer
	jqCmd.Stderr = &jqStderr

	// Start downstream command (jq) first to avoid race conditions
	if err := jqCmd.Start(); err != nil {
		return "", fmt.Errorf("failed to start jq: %w, stderr: %s", err, jqStderr.String())
	}

	// Start upstream command (aliyun)
	if err := aliyunCmd.Start(); err != nil {
		// Clean up jq process if aliyun fails to start
		_ = jqCmd.Process.Kill()
		_ = jqCmd.Wait()
		return "", fmt.Errorf("failed to start aliyun: %w, stderr: %s", err, aliyunStderr.String())
