		errMsg := fmt.Sprintf("aliyun command failed: %v, stderr: %s", err, aliyunStderr.String())
		if jqErrMsg := jqStderr.String(); jqErrMsg != "" {
			errMsg += fmt.Sprintf("; jq stderr: %s", jqErrMsg)
		}
		return "", fmt.Errorf("%s", errMsg)
