// processes the output with jq, and saves it to the specified file.
// Returns the stdout of the jq command (the formatted SLB data) and any error encountered.
func QuerySLBAndExport(loadBalancerName string, outputFile string) (string, error) {
	// Validate input parameters
	if loadBalancerName == "" {
		return "", fmt.Errorf("loadBalancerName cannot be empty")
	}
	if outputFile == "" {
		return "", fmt.Errorf("outputFile cannot be empty")
	}

	// Create the aliyun command with direct arguments (no shell, avoids injection)
	aliyunCmd := exec.Command("aliyun", "slb", "DescribeLoadBalancers", "--LoadBalancerName", loadBalancerName)

	// Create the jq command with the filter (no quotes needed, as we pass directly)
	jqCmd := exec.Command("jq", ".LoadBalancers.LoadBalancer[]")

	// Connect aliyun's stdout to jq's stdin
	aliyunStdout, err := aliyunCmd.StdoutPipe()
	if err != nil {
		return "", fmt.Errorf("failed to create aliyun stdout pipe: %w", err)
	}
	jqCmd.Stdin = aliyunStdout

	// Buffers to capture outputs and errors
	var aliyunStderr bytes.Buffer
	var jqStderr bytes.Buffer
	var jqStdout bytes.Buffer

	// Set stderr buffers for both commands
	aliyunCmd.Stderr = &aliyunStderr
	jqCmd.Stderr = &jqStderr

	// Open the output file for writing (create/truncate)
	outFile, err := os.Create(outputFile)
	if err != nil {
		return "", fmt.Errorf("failed to create output file: %w", err)
	}
	defer outFile.Close()

	// Write jq's stdout to both the buffer (for return value) and the output file
	jqCmd.Stdout = io.MultiWriter(&jqStdout, outFile)

	// Start both commands
	if err := aliyunCmd.Start(); err != nil {
		return "", fmt.Errorf("failed to start aliyun command: %w, stderr: %s", err, aliyunStderr.String())
	}
	if err := jqCmd.Start(); err != nil {
		// Clean up aliyun command if jq fails to start
		aliyunCmd.Wait()
		return "", fmt.Errorf("failed to start jq command: %w, stderr: %s", err, jqStderr.String())
	}

	// Wait for aliyun command to complete
	if err := aliyunCmd.Wait(); err != nil {
		// Wait for jq to clean up
		jqCmd.Wait()
		return "", fmt.Errorf("aliyun command failed: %w, stderr: %s", err, aliyunStderr.String())
	}

	// Wait for jq command to complete
	if err := jqCmd.Wait(); err != nil {
		return "", fmt.Errorf("jq command failed: %w, stderr: %s", err, jqStderr.String())
	}

	// Return the jq output (formatted SLB data)
	return jqStdout.String(), nil
}

