	jqCmd.Stdin = aliyunStdout

	// Start jq first (it will wait for input from aliyun)
	if err := jqCmd.Start(); err != nil {
		return "", fmt.Errorf("failed to start jq: %w", err)
	}

	// Start aliyun command
	if err := aliyunCmd.Start(); err != nil {
		// Clean up jq process if aliyun fails to start
		_ = jqCmd.Wait()
		return combinedStderr.String(), fmt.Errorf("failed to start aliyun: %w", err)
	}

	// Wait for aliyun to complete
	if err := aliyunCmd.Wait(); err != nil {
		// Ensure jq is cleaned up even if aliyun fails
		_ = jqCmd.Wait()
		return combinedStderr.String(), fmt.Errorf("aliyun failed: %w, output: %s", err, combinedStderr.String())
	}

	// Wait for jq to complete processing
	if err := jqCmd.Wait(); err != nil {
		return combinedStderr.String(), fmt.Errorf("jq failed: %w, output: %s", err, combinedStderr.String())
	}

