// QuerySLBAndExport executes the aliyun SLB describe command, pipes the result to jq for formatting,
// and writes the output to the specified file. It returns the command execution stderr output and any error encountered.
func QuerySLBAndExport(loadBalancerName string, outputFile string) (string, error) {
	// Initialize the aliyun CLI command
	aliyunCmd := exec.Command("aliyun", "slb", "DescribeLoadBalancers", "--LoadBalancerName", loadBalancerName)
	// Initialize the jq command with the specified filter (no quotes needed as we bypass shell parsing)
	jqCmd := exec.Command("jq", ".LoadBalancers.LoadBalancer[]")

	// Capture stderr from both commands for debugging/result
	var stderrBuffer bytes.Buffer
	aliyunCmd.Stderr = &stderrBuffer
	jqCmd.Stderr = &stderrBuffer

	// Create pipe between aliyun command's stdout and jq command's stdin
	pipe, err := aliyunCmd.StdoutPipe()
	if err != nil {
		return stderrBuffer.String(), fmt.Errorf("failed to create inter-command pipe: %w", err)
	}
	jqCmd.Stdin = pipe

	// Open the output file for writing (truncate if exists, create if missing)
	outFile, err := os.Create(outputFile)
	if err != nil {
		return stderrBuffer.String(), fmt.Errorf("failed to create output file: %w", err)
	}
	defer outFile.Close() // Ensure file is closed when function exits
	jqCmd.Stdout = outFile

	// Start jq first (the downstream command that reads input)
	if err := jqCmd.Start(); err != nil {
		return stderrBuffer.String(), fmt.Errorf("failed to start jq command: %w", err)
	}

	// Start the aliyun command (the upstream command that produces input)
	if err := aliyunCmd.Start(); err != nil {
		// Clean up jq process if aliyun fails to start
		_ = jqCmd.Process.Kill()
		_ = jqCmd.Wait()
		return stderrBuffer.String(), fmt.Errorf("failed to start aliyun command: %w", err)
	}

	// Wait for aliyun command to complete
	aliyunErr := aliyunCmd.Wait()
	// Wait for jq command to complete (will exit after aliyun closes the pipe)
	jqErr := jqCmd.Wait()

	// Ensure all data is flushed to disk
	if syncErr := outFile.Sync(); syncErr != nil {
		if aliyunErr == nil && jqErr == nil {
			return stderrBuffer.String(), fmt.Errorf("failed to sync output file to disk: %w", syncErr)
		}
	}

	// Check for command execution errors
	if aliyunErr != nil {
		return stderrBuffer.String(), fmt.Errorf("aliyun command execution failed: %w", aliyunErr)
	}
	if jqErr != nil {
		return stderrBuffer.String(), fmt.Errorf("jq command execution failed: %w", jqErr)
	}

	// Return stderr output (empty on success) and no error
	return stderrBuffer.String(), nil
}

func main() {
	// Example command-line usage: go run main.go <LoadBalancerName> <OutputFile>
	if len(os.Args) != 3 {
		fmt.Fprintf(os.Stderr, "Usage: %s <loadBalancerName> <outputFile>\n", os.Args[0])
		os.Exit(1)
	}

	loadBalancerName := os.Args[1]
	outputFile := os.Args[2]

	result, err := QuerySLBAndExport(loadBalancerName, outputFile)
	if err != nil {
		fmt.Fprintf(os.Stderr, "Error executing command: %v\n", err)
		if result != "" {
