		}
		os.Exit(1)
	}

	if result != "" {
		fmt.Fprintf(os.Stdout, "Command stderr output:\n%s\n", result)
	}
	fmt.Fprintf(os.Stdout, "Successfully exported SLB information to %s\n", outputFile)
}

