// QuerySLBAndExport runs the aliyun SLB describe command, pipes output to jq, and writes to the specified file
func QuerySLBAndExport(loadBalancerName string, outputFile string) (string, error) {
	// Create or truncate the output file
	outFile, err := os.Create(outputFile)
	if err!= nil {
		return "", fmt.Errorf("failed to open output file: %w", err)
	}
	defer outFile.Close()

	// Initialize the two commands for the pipeline
	aliyunCmd := exec.Command("aliyun", "slb", "DescribeLoadBalancers", "--LoadBalancerName", loadBalancerName)
	jqCmd := exec.Command("jq", ".LoadBalancers.LoadBalancer[]")

	// Set up buffers to capture stderr from both commands
	var aliyunErrBuf, jqErrBuf bytes.Buffer
	aliyunCmd.Stderr = &aliyunErrBuf
	jqCmd.Stderr = &jqErrBuf

	// Connect aliyun's stdout to jq's stdin
	jqCmd.Stdin, err = aliyunCmd.StdoutPipe()
	if err!= nil {
		combinedErr := fmt.Sprintf("aliyun stderr: %s\njq stderr: %s", aliyunErrBuf.String(), jqErrBuf.String())
		return combinedErr, fmt.Errorf("failed to create pipe between commands: %w", err)
	}

	// Direct jq's stdout to the output file
	jqCmd.Stdout = outFile

	// Start the downstream (jq) command first
	if err := jqCmd.Start(); err!= nil {
		combinedErr := fmt.Sprintf("aliyun stderr: %s\njq stderr: %s", aliyunErrBuf.String(), jqErrBuf.String())
		return combinedErr, fmt.Errorf("failed to start jq command: %w", err)
	}

	// Run the upstream (aliyun) command (will block until completion)
	if err := aliyunCmd.Run(); err!= nil {
		// Wait for jq to finish even if aliyun fails
		jqWaitErr := jqCmd.Wait()
		combinedErr := fmt.Sprintf("aliyun stderr: %s\njq stderr: %s", aliyunErrBuf.String(), jqErrBuf.String())
		var finalErr error
		if jqWaitErr!= nil {
			finalErr = fmt.Errorf("aliyun command failed: %w; jq command failed: %w", err, jqWaitErr)
		} else {
			finalErr = fmt.Errorf("aliyun command failed: %w", err)
		}
		return combinedErr, finalErr
	}

	// Wait for jq to complete after aliyun finishes
	if err := jqCmd.Wait(); err!= nil {
		combinedErr := fmt.Sprintf("aliyun stderr: %s\njq stderr: %s", aliyunErrBuf.String(), jqErrBuf.String())
		return combinedErr, fmt.Errorf("jq command failed: %w", err)
	}

	// Return combined stderr output and no error on success
	combinedOutput := fmt.Sprintf("aliyun stderr: %s\njq stderr: %s", aliyunErrBuf.String(), jqErrBuf.String())
	return combinedOutput, nil
}

func main() {
	if len(os.Args)!= 3 {
		fmt.Fprintf(os.Stderr, "Usage: %s <load-balancer-name> <output-file>\n", os.Args[0])
