	if strings.ContainsAny(loadBalancerName, "`$\n\r\t|>") || strings.ContainsAny(outputFile, "`$\n\r\t|>") {
		return "", fmt.Errorf("invalid characters in input parameters")
	}

	// Create output file
	outFile, err := os.Create(outputFile)
	if err != nil {
		return "", fmt.Errorf("failed to create output file: %w", err)
	}
	defer outFile.Close()

	// Prepare aliyun command
	aliyunCmd := exec.Command("aliyun", "slb", "DescribeLoadBalancers", "--LoadBalancerName", loadBalancerName)
	var aliyunStderr bytes.Buffer
	aliyunCmd.Stderr = &aliyunStderr

	// Prepare jq command
	jqCmd := exec.Command("jq", ".LoadBalancers.LoadBalancer[]")
	var jqStderr, jqStdout bytes.Buffer
	jqCmd.Stderr = &jqStderr
	jqCmd.Stdout = &jqStdout

	// Connect aliyun's stdout to jq's stdin
	aliyunPipe, err := aliyunCmd.StdoutPipe()
	if err != nil {
		return "", fmt.Errorf("failed to create pipe for aliyun: %w", err)
	}
	jqCmd.Stdin = aliyunPipe

	// Start aliyun command
	if err := aliyunCmd.Start(); err != nil {
		return "", fmt.Errorf("failed to start aliyun command: %w, stderr: %s", err, aliyunStderr.String())
	}

	// Start jq command
	if err := jqCmd.Start(); err != nil {
		// Wait for aliyun to clean up
		aliyunCmd.Wait()
		return "", fmt.Errorf("failed to start jq command: %w, stderr: %s", err, jqStderr.String())
	}

	// Wait for both commands to finish
	jqErr := jqCmd.Wait()
	aliyunErr := aliyunCmd.Wait()

	// Write jq's output to the file
	if _, err := outFile.Write(jqStdout.Bytes()); err != nil {
		return "", fmt.Errorf("failed to write to output file: %w", err)
	}

	// Combine stderr outputs
	var combinedStderr string
	if aliyunStderr.Len() > 0 {
		combinedStderr += "aliyun stderr: " + aliyunStderr.String()
	}
	if jqStderr.Len() > 0 {
		if combinedStderr != "" {
			combinedStderr += "\n"
		}
		combinedStderr += "jq stderr: " + jqStderr.String()
	}

	// Check for errors
	if aliyunErr != nil {
		return jqStdout.String(), fmt.Errorf("aliyun command failed: %w, %s", aliyunErr, combinedStderr)
	}
	if jqErr != nil {
		return jqStdout.String(), fmt.Errorf("jq command failed: %w, %s", jqErr, combinedStderr)
	}

	// Success
	return jqStdout.String(), nil
}

