package main

import (
	"bytes"
	"fmt"
	"os"
	"os/exec"
)

// QuerySLBAndExport executes the aliyun CLI command to describe SLB,
// processes the output with jq, and saves it to the specified file.
// Returns the combined stderr output of the commands and any error encountered.
func QuerySLBAndExport(loadBalancerName string, outputFile string) (string, error) {
	// Basic validation: ensure parameters are not empty
	if loadBalancerName == "" {
		return "", fmt.Errorf("loadBalancerName cannot be empty")
	}
	if outputFile == "" {
		return "", fmt.Errorf("outputFile cannot be empty")
	}

	// Set up the aliyun command with direct arguments (no shell injection risk)
	aliyunCmd := exec.Command("aliyun", "slb", "DescribeLoadBalancers", "--LoadBalancerName", loadBalancerName)

	// Set up the jq command with the filter (no quotes needed as we avoid shell)
	jqCmd := exec.Command("jq", ".LoadBalancers.LoadBalancer[]")

	// Connect aliyun's stdout to jq's stdin
	aliyunStdout, err := aliyunCmd.StdoutPipe()
	if err != nil {
		return "", fmt.Errorf("failed to create stdout pipe for aliyun: %w", err)
	}
	jqCmd.Stdin = aliyunStdout

	// Create the output file
	outFile, err := os.Create(outputFile)
	if err != nil {
		return "", fmt.Errorf("failed to create output file %q: %w", outputFile, err)
	}
	defer outFile.Close()

	// Direct jq's stdout to the output file
	jqCmd.Stdout = outFile

	// Capture stderr from both commands to include in the result
	var aliyunStderr, jqStderr bytes.Buffer
	aliyunCmd.Stderr = &aliyunStderr
	jqCmd.Stderr = &jqStderr

	// Start the aliyun command
	if err := aliyunCmd.Start(); err != nil {
		return aliyunStderr.String(), fmt.Errorf("failed to start aliyun command: %w", err)
	}

	// Start the jq command
	if err := jqCmd.Start(); err != nil {
		// Wait for aliyun to prevent zombie process
		aliyunCmd.Wait()
		combinedOutput := aliyunStderr.String()
		if jqStderr.Len() > 0 {
			combinedOutput += "\n" + jqStderr.String()
		}
		return combinedOutput, fmt.Errorf("failed to start jq command: %w", err)
	}

	// Wait for both commands to complete and collect errors
	var finalErr error
	if err := aliyunCmd.Wait(); err != nil {
		finalErr = fmt.Errorf("aliyun command failed: %w", err)
	}
	if err := jqCmd.Wait(); err != nil {
		if finalErr != nil {
			finalErr = fmt.Errorf("%v; jq command failed: %w", finalErr, err)
		} else {
			finalErr = fmt.Errorf("jq command failed: %w", err)
		}
	}

	// Combine the stderr outputs
	combinedOutput := aliyunStderr.String()
	if jqStderr.Len() > 0 {
		if combinedOutput != "" {
			combinedOutput += "\n"
		}
		combinedOutput += jqStderr.String()
	}

	if finalErr != nil {
		return combinedOutput, fmt.Errorf("pipeline execution failed: %w, output: %s", finalErr, combinedOutput)
	}

	return combinedOutput, nil
}

