package main

import (
	"bytes"
	"fmt"
	"io"
	"os"
	"os/exec"
)

// QuerySLBAndExport executes the aliyun CLI command to describe SLB,
// processes the output with jq, and saves it to the specified file.
// Returns the stdout of the command pipeline and any error encountered.
func QuerySLBAndExport(loadBalancerName string, outputFile string) (string, error) {
	// Set up the aliyun command with the given load balancer name
	cmdAliyun := exec.Command("aliyun", "slb", "DescribeLoadBalancers", "--LoadBalancerName", loadBalancerName)

	// Set up the jq command to format the output
	cmdJq := exec.Command("jq", ".LoadBalancers.LoadBalancer[]")

	// Create a pipe to connect aliyun's stdout to jq's stdin
	pipe, err := cmdAliyun.StdoutPipe()
	if err != nil {
		return "", fmt.Errorf("failed to create pipe between commands: %w", err)
	}
	cmdJq.Stdin = pipe

	// Buffers to capture stdout and stderr
	var stdoutBuf bytes.Buffer
	var stderrAliyun bytes.Buffer
	var stderrJq bytes.Buffer

	// Capture aliyun's stderr
	cmdAliyun.Stderr = &stderrAliyun

	// Create the output file
	outFile, err := os.Create(outputFile)
	if err != nil {
		return "", fmt.Errorf("failed to create output file %q: %w", outputFile, err)
	}
	defer outFile.Close()

	// Write jq's stdout to both the buffer (for return) and the output file
	multiWriter := io.MultiWriter(&stdoutBuf, outFile)
	cmdJq.Stdout = multiWriter
	cmdJq.Stderr = &stderrJq

	// Start both commands
	if err := cmdAliyun.Start(); err != nil {
		return "", fmt.Errorf("failed to start aliyun command: %w", err)
	}
	if err := cmdJq.Start(); err != nil {
		return "", fmt.Errorf("failed to start jq command: %w", err)
	}

	// Wait for both commands to complete
	errAliyun := cmdAliyun.Wait()
	errJq := cmdJq.Wait()

	// Combine stderr from both commands for error reporting
	combinedStderr := ""
	if stderrAliyun.Len() > 0 {
		combinedStderr += "aliyun stderr:\n" + stderrAliyun.String()
	}
	if stderrJq.Len() > 0 {
		if combinedStderr != "" {
			combinedStderr += "\n"
		}
		combinedStderr += "jq stderr:\n" + stderrJq.String()
	}

	// Check for errors from either command
	if errAliyun != nil {
		return stdoutBuf.String(), fmt.Errorf("aliyun command failed: %w%s", errAliyun, func() string {
			if combinedStderr != "" {
				return "\n" + combinedStderr
			}
			return ""
		}())
	}
	if errJq != nil {
		return stdoutBuf.String(), fmt.Errorf("jq command failed: %w%s", errJq, func() string {
			if combinedStderr != "" {
				return "\n" + combinedStderr
			}
			return ""
		}())
	}

	// Return the captured stdout (same as written to the file)
	return stdoutBuf.String(), nil
}

