	// Wait for jq to complete processing
	if err := jqCmd.Wait(); err != nil {
		return stderrBuf.String(), fmt.Errorf("jq command execution failed: %w", err)
	}

	// Return any stderr output and no error on success
	return stderrBuf.String(), nil
}

