// QuerySLBAndExport executes the aliyun CLI command to describe SLB,
// processes the output with jq, and saves it to the specified file.
// Returns the combined stderr of the commands and any error encountered.
func QuerySLBAndExport(loadBalancerName string, outputFile string) (string, error) {
	// Create the aliyun CLI command with direct arguments to avoid shell injection
	aliyunCmd := exec.Command("aliyun", "slb", "DescribeLoadBalancers", "--LoadBalancerName", loadBalancerName)
	// Create the jq command with the filter as a direct argument
	jqCmd := exec.Command("jq", ".LoadBalancers.LoadBalancer[]")

	// Buffers to capture stderr from both commands
	var aliyunStderr, jqStderr bytes.Buffer
	aliyunCmd.Stderr = &aliyunStderr
	jqCmd.Stderr = &jqStderr

	// Pipe aliyun's stdout to jq's stdin
	jqStdin, err := aliyunCmd.StdoutPipe()
	if err != nil {
		return "", fmt.Errorf("failed to create pipe for aliyun output: %w", err)
	}
	jqCmd.Stdin = jqStdin

	// Open the output file (create if not exists, truncate if exists)
	outFile, err := os.OpenFile(outputFile, os.O_WRONLY|os.O_CREATE|os.O_TRUNC, 0644)
	if err != nil {
		return "", fmt.Errorf("failed to open output file %q: %w", outputFile, err)
	}
	defer outFile.Close()

	// Redirect jq's stdout to the output file
	jqCmd.Stdout = outFile

	// Start jq first so it's ready to receive input from aliyun
	if err := jqCmd.Start(); err != nil {
		combinedStderr := aliyunStderr.String() + jqStderr.String()
		return combinedStderr, fmt.Errorf("failed to start jq: %w", err)
	}

	// Start the aliyun command
	if err := aliyunCmd.Start(); err != nil {
		combinedStderr := aliyunStderr.String() + jqStderr.String()
		// Clean up jq process if aliyun fails to start
		_ = jqCmd.Process.Kill()
		_ = jqCmd.Wait()
		return combinedStderr, fmt.Errorf("failed to start aliyun command: %w", err)
	}

	// Wait for aliyun to complete
	if err := aliyunCmd.Wait(); err != nil {
		combinedStderr := aliyunStderr.String() + jqStderr.String()
		// Wait for jq to exit even if aliyun fails
		_ = jqCmd.Wait()
		return combinedStderr, fmt.Errorf("aliyun command failed: %w", err)
	}

	// Wait for jq to complete processing the input
	if err := jqCmd.Wait(); err != nil {
		combinedStderr := aliyunStderr.String() + jqStderr.String()
		return combinedStderr, fmt.Errorf("jq command failed: %w", err)
	}

	// Return combined stderr (should be empty on success)
	return aliyunStderr.String() + jqStderr.String(), nil
}

