// QuerySLBAndExport executes the aliyun SLB query command, pipes to jq, and writes output to file
func QuerySLBAndExport(loadBalancerName string, outputFile string) (string, error) {
	// Create and open the output file (truncate if exists)
	outFile, err := os.Create(outputFile)
	if err!= nil {
		return "", fmt.Errorf("failed to create output file: %w", err)
	}
	defer outFile.Close()

	// Buffer to capture stderr from both commands
	var stderr bytes.Buffer

	// Configure the aliyun command
	aliyunCmd := exec.Command("aliyun", "slb", "DescribeLoadBalancers", "--LoadBalancerName", loadBalancerName)
	aliyunCmd.Stderr = &stderr

	// Configure the jq command
	jqCmd := exec.Command("jq", ".LoadBalancers.LoadBalancer[]")
	jqCmd.Stderr = &stderr
	jqCmd.Stdout = outFile

	// Connect stdout of aliyun to stdin of jq
	jqCmd.Stdin, err = aliyunCmd.StdoutPipe()
	if err!= nil {
		return stderr.String(), fmt.Errorf("failed to create pipe between commands: %w", err)
	}

	// Start jq first  it's ready to receive input
	if err := jqCmd.Start(); err!= nil {
		return stderr.String(), fmt.Errorf("failed to start jq command: %w", err)
	}

	// Run the aliyun command (starts and waits for completion)
	if err := aliyunCmd.Run(); err!= nil {
		// Wait for jq to exit to avoid zombie processes
		_ = jqCmd.Wait()
		return stderr.String(), fmt.Errorf("aliyun command execution failed: %w", err)
	}

	// Wait for jq to finish processing input
	if err := jqCmd.Wait(); err!= nil {
		return stderr.String(), fmt.Errorf("jq command execution failed: %w", err)
	}

	return stderr.String(), nil
}

func main() {
	if len(os.Args)!= 3 {
		fmt.Fprintf(os.Stderr, "Usage: %s <loadBalancerName> <outputFile>\n", os.Args[0])
		os.Exit(1)
	}

	loadBalancerName := os.Args[1]
	outputFile := os.Args[2]

	stderrOutput, err := QuerySLBAndExport(loadBalancerName, outputFile)

	if stderrOutput!= "" {
		fmt.Fprintln(os.Stderr, "Command stderr output:")
		fmt.Fprintln(os.Stderr, stderrOutput)
	}

	if err!= nil {
		fmt.Fprintf(os.Stderr, "Error: %v\n", err)
		os.Exit(1)
	}

	fmt.Printf("Successfully exported SLB information to %s\n", outputFile)
}

